package ru.memearena.user.application;
import org.springframework.http.HttpStatus; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ru.memearena.error.*; import ru.memearena.user.domain.UserProfile; import ru.memearena.user.infrastructure.UserProfileRepository; import java.time.*; import java.util.UUID; import java.util.regex.Pattern;
@Service public class UserProfileService { private static final Pattern NICK=Pattern.compile("^[\p{IsCyrillic}A-Za-z0-9_-]{3,30}$"); private final UserProfileRepository repo; private final Clock clock; public UserProfileService(UserProfileRepository repo,Clock clock){this.repo=repo;this.clock=clock;} @Transactional public UserProfile createGuest(String raw){String n=normalize(raw); if(repo.existsByNicknameIgnoreCase(n)) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.NICKNAME_ALREADY_EXISTS,"Nickname already exists"); return repo.save(new UserProfile(UUID.randomUUID(),n,Instant.now(clock)));} @Transactional(readOnly=true) public UserProfile get(UUID id){return repo.findById(id).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ErrorCode.USER_NOT_FOUND,"User not found"));} public static String normalize(String raw){String n=raw==null?"":raw.trim(); if(!NICK.matcher(n).matches()) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Invalid nickname"); return n;} }
